import{_ as e,c as a,o as p,d as t}from"./app.564110b9.js";const u=JSON.parse('{"title":"\u6280\u672F\u63D0\u5347","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u5B66\u4E60\u53C2\u8003","slug":"\u5B66\u4E60\u53C2\u8003","link":"#\u5B66\u4E60\u53C2\u8003","children":[]},{"level":2,"title":"\u524D\u7AEF\u57FA\u5EFA\u9879\u76EE\uFF1A","slug":"\u524D\u7AEF\u57FA\u5EFA\u9879\u76EE\uFF1A","link":"#\u524D\u7AEF\u57FA\u5EFA\u9879\u76EE\uFF1A","children":[]}],"relativePath":"Document/\u6280\u672F\u63D0\u5347\u548C\u804C\u4E1A\u89C4\u5212/skillUpgrading.md","lastUpdated":1661228667000}'),r={name:"Document/\u6280\u672F\u63D0\u5347\u548C\u804C\u4E1A\u89C4\u5212/skillUpgrading.md"},i=t('<h1 id="\u6280\u672F\u63D0\u5347" tabindex="-1">\u6280\u672F\u63D0\u5347 <a class="header-anchor" href="#\u6280\u672F\u63D0\u5347" aria-hidden="true">#</a></h1><h2 id="\u5B66\u4E60\u53C2\u8003" tabindex="-1">\u5B66\u4E60\u53C2\u8003 <a class="header-anchor" href="#\u5B66\u4E60\u53C2\u8003" aria-hidden="true">#</a></h2><p>\u7B2C1\u5173 \u4E0D\u754F\u60E7,\u9700\u8981\u4EC0\u4E48\u5C31\u5B66\u4EC0\u4E48</p><p>\u7B2C\u2489\u5173 \u4E86\u89E3EggJS\u7684\u57FA\u672C\u6982\u5FF5\u3001\u5B83\u7684\u4F7F\u7528\u573A\u666F\uFF0C\u770B\u770B\u76F8\u5173\u7684\u535A\u5BA2</p><p>\u7B2C3\u5173 \u628A EggJS\u76F8\u5173\u7684Demo\u5DE5\u7A0B/\u4ED3\u5E93\u4E0B\u8F7D\u5230\u672C\u5730\uFF0C\u7C97\u7565\u770B\u770B\u76EE\u5F55\u7ED3\u6784</p><p>\u7B2C4\u5173 \u6839\u636E\u5B98\u65B9\u914D\u5957\u7684\u6559\u7A0B(\u6216\u5E02\u9762\u4E0A\u514D\u8D39/\u4ED8\u8D39\u7684\u6559\u7A0B)\uFF0C\u770B\u770B\u5982\u4F55\u5728\u547D\u4EE4\u884C\u4E2D\u628A\u5B83runy\u8FD0\u884C\u8D77\u6765</p><p>\u7B2C5\u5173\u8FDB\u4E00\u6B65\u9605\u8BFB\u5B83\u7684\u6587\u6863\uFF0C\u4E86\u89E3\u5404\u79CD\u914D\u7F6E\u3001\u5F00\u5173\uFF0C\u9010\u4E2A\u6D4B\u8BD5\u4E0B\uFF0C\u5B8C\u6574\u7684\u638C\u63E1\u5B83\u7684\u5177\u4F53\u4F7F\u7528\u65B9\u6CD5</p><p>\u7B2C6\u5173 \u770B\u770B\u5B83\u5982\u4F55\u8FD0\u7EF4\u53D1\u5E03\uFF0C\u627E\u4E2A\u73A9\u5177\u9879\u76EE\uFF0C\u5B8C\u6574\u7684\u8D70\u4E00\u904D\u4ECE0\u52301\u7684\u6784\u5EFA\u53D1\u5E03\u8FC7\u7A0B</p><p>\u7B2C7\u5173 \u628A\u5B83\u5F15\u5165\u5230\u81EA\u5DF1\u7684\u4E2A\u4EBA/\u4E1A\u52A1\u9879\u76EE\u4E2D\uFF0C\u7ED9\u5B83\u7F16\u5199\u4E2D\u95F4\u4EF6\u6216\u8005\u63D2\u4EF6</p><p>\u7B2C8\u5173 \u628A\u5B83\u5F15\u5165\u5230\u751F\u4EA7\u73AF\u5883\u4E2D\uFF0C\u770B\u770B\u5B83\u5728\u771F\u5B9E\u73AF\u5883\u4E2D\u8868\u73B0\u5982\u4F55\uFF0C\u5F53\u7136\u53EF\u4EE5\u591A\u505A\u4E00\u4E9B\u6027\u80FD\u538B\u6D4B</p><p>\u7B2C9\u5173 \u5F00\u53D1\u548C\u8FD0\u884C\u4E00\u6BB5\u65F6\u95F4\u540E\uFF0C\u770B\u770B\u5B83\u6709\u6CA1\u6709\u4EC0\u4E48\u62A5\u9519\u6216\u8005Bug\uFF0C\u7F3A\u9677,\u5C1D\u8BD5\u4FEE\u590D\u5B83</p><p>\u7B2C10\u5173 \u5982\u679C\u4FEE\u590D\u4E0D\u4E86\uFF0C\u5C31\u9605\u8BFBEggJS\u6E90\u7801\uFF0C\u627E\u5230\u6709\u95EE\u9898\u7684\u4F4D\u7F6E\uFF0C\u5206\u6790\u4E0B\u8FD9\u91CC\u7684\u8C03\u7528\u6D41\u7A0B</p><p>\u7B2C11\u5173 \u5982\u679C\u662F\u8DE8\u9886\u57DF\u95EE\u9898\uFF0C\u8865\u5145\u4E0E\u95EE\u9898\u76F8\u5173\u7684\u77E5\u8BC6\uFF08\u6BD4\u5982\u7F51\u7EDC\u77E5\u8BC6)\uFE50\u6765\u5BFB\u627E\u7406\u8BBA\u652F\u6491</p><p>\u7B2C12\u5173 \u4F9D\u7136\u89E3\u51B3\u4E0D\u4E86\uFF0C\u5C31\u5404\u79CDGoogle/issue/\u963F\u91CC\u4E91\u5DE5\u5355/\u4ED8\u8D39\u8BF7\u6559....\u4E0D\u62E9\u624B\u6BB5\uFF0C\u770B\u5982\u4F55\u6C42\u52A9\u641E\u5B9A</p><p>\u7B2C13\u5173 \u6700\u7EC8\u4F9D\u7136\u8981\u5230\u6E90\u7801\u5C42\u9762\uFF0C\u9010\u884CDebug\uFF0C\u5F7B\u5E95\u628A\u8BE5\u6D41\u7A0B\u5F04\u901A\uFF0C\u95EE\u9898\u70B9\u548C\u89E3\u51B3\u65B9\u6848\u641E\u61C2</p><p>\u7B2C14\u5173 \u63D0\u4EA4\u4EE3\u7801\u7684Fix/Feature\u4E4B\u7C7B\u7684\u5206\u652F\uFF0C\u5411\u5B98\u65B9\u793E\u533A\u63D0\u4EA4\u7F3A\u9677\u4FEE\u590D\u540E\u7684\u4EE3\u7801</p><p>\u7B2C15\u5173 \u628A\u8FD9\u4E9B\u8FC7\u7A0B\u4E2D\u5178\u578B\u7684\u95EE\u9898\u548C\u6C89\u6DC0\u7684\u77E5\u8BC6,\u6574\u7406\u6210\u4E00\u7BC7\u7BC7\u7684\u6587\u6863\uFF0C\u8BB0\u5F55\u4E0B\u6765</p><p>\u7B2C16\u5173\u628A\u5982\u4E0A\u7684\u6C89\u6DC0\uFF0C\u901A\u8FC7\u5927\u4F1A/\u516C\u5F00\u5206\u4EAB/\u76F4\u64AD...\uFF0C\u4EB2\u53E3\u8BB2\u51FA\u6765\uFF0C\u6559\u7ED9\u522B\u4EBA\uFF0C\u589E\u5F3A\u81EA\u5DF1\u7684\u7406\u8BBA\u4F53\u7CFB</p><p>\u7B2C17\u5173 \u5982\u6B64\u53CD\u590D\u5982\u4E0A7~16\uFF0C\u6839\u636E\u81EA\u5DF1\u7684\u9700\u6C42\uFF0C\u4E00\u70B9\u70B9\u5BF9EggJS\u505A\u8FDB\u4E00\u6B65\u7684\u5B9A\u5236\u6539\u9020/\u4E8C\u6B21\u5F00\u53D1</p><p>\u7B2C18\u5173 \u73A9\u6E9C\u4E86\u4E4B\u540E\uFF0C\u5F00\u53D1\u4E00\u4E2A\u6BD4EggJS\u66F4\u597D\u7684\u6846\u67B6\uFF0C\u6216\u8005\u81EA\u7814\u66F4\u7B26\u5408\u9700\u6C42\u7684\u65B0\u7684\u66FF\u4EE3\u65B9\u6848</p><hr><h2 id="\u524D\u7AEF\u57FA\u5EFA\u9879\u76EE\uFF1A" tabindex="-1">\u524D\u7AEF\u57FA\u5EFA\u9879\u76EE\uFF1A <a class="header-anchor" href="#\u524D\u7AEF\u57FA\u5EFA\u9879\u76EE\uFF1A" aria-hidden="true">#</a></h2>',22),n=[i];function d(s,l,o,c,_,h){return p(),a("div",null,n)}const m=e(r,[["render",d]]);export{u as __pageData,m as default};
